3.4 조건문과 반복문

3.4.1 if/else 문

# 기본 if/else 구조
dose_recommendation &lt;- function(c0_level) {
  if (c0_level &lt; 100) {
    "용량 증가 고려"
  } else if (c0_level &lt;= 200) {
    "현재 용량 유지"
  } else {
    "용량 감소 고려"
  }
}

dose_recommendation(180)  # "현재 용량 유지"
dose_recommendation(250)  # "용량 감소 고려"







경고if_else() vs ifelse() vs if/else




if/else: 단일 조건 평가 (스칼라). 벡터화되지 않음
ifelse(): 벡터화된 조건문. 타입 불일치 주의
dplyr::if_else(): 벡터화, 타입 엄격 검사. 권장
dplyr::case_when(): 여러 조건을 순차적으로 평가. 가장 유연


# 벡터에서는 if_else() 또는 case_when() 사용
csa_tdm |&gt;
  mutate(
    range_flag = if_else(concentration &gt; 200, "High", "Normal")
  )





3.4.2 for 반복문

# 환자별 반복 작업 (for문)
patient_ids &lt;- unique(csa_tdm$patient_id)

results &lt;- list()
for (i in seq_along(patient_ids)) {
  pt_data &lt;- csa_tdm |&gt;
    filter(patient_id == patient_ids[i], sample_type == "C0")

  results[[i]] &lt;- tibble(
    patient_id = patient_ids[i],
    n_obs = nrow(pt_data),
    mean_c0 = mean(pt_data$concentration, na.rm = TRUE)
  )
}

results_df &lt;- bind_rows(results)



3.4.3 apply 계열 vs purrr::map()
R에서 반복 작업을 수행하는 방법은 여러 가지가 있습니다. 전통적인 apply 계열과 tidyverse의 purrr::map() 계열을 비교해 보겠습니다:

# sapply: 각 환자의 평균 C0 농도
sapply(patient_ids, function(pid) {
  csa_tdm |&gt;
    filter(patient_id == pid, sample_type == "C0") |&gt;
    pull(concentration) |&gt;
    mean(na.rm = TRUE)
})

# purrr::map_dbl: 동일한 작업을 tidyverse 스타일로
patient_ids |&gt;
  map_dbl(~ {
    csa_tdm |&gt;
      filter(patient_id == .x, sample_type == "C0") |&gt;
      pull(concentration) |&gt;
      mean(na.rm = TRUE)
  })


# purrr::map_dfr: 결과를 데이터프레임으로 합치기
patient_summary &lt;- patient_ids |&gt;
  map_dfr(~ {
    pt_data &lt;- csa_tdm |&gt;
      filter(patient_id == .x, sample_type == "C0")

    tibble(
      patient_id = .x,
      n_obs = nrow(pt_data),
      mean_c0 = mean(pt_data$concentration, na.rm = TRUE),
      sd_c0 = sd(pt_data$concentration, na.rm = TRUE)
    )
  })







힌트group_by()로 대체 가능한 경우



위 예제처럼 그룹별 요약을 수행하는 경우, 대부분 group_by() + summarise()로 더 간결하게 작성할 수 있습니다. map()은 그룹별로 모델 피팅, 그래프 생성 등 복잡한 작업에 더 적합합니다.

4.5 결측치(NA) 및 BLQ 처리

4.5.1 NA 탐지 및 처리

# NA 확인
sum(is.na(csa_tdm$concentration))           # NA 개수
mean(is.na(csa_tdm$concentration)) * 100    # NA 비율 (%)

# 열별 NA 개수 확인
csa_tdm |&gt;
  summarise(across(everything(), ~ sum(is.na(.x))))

# 열별 NA 비율 확인
csa_tdm |&gt;
  summarise(across(everything(), ~ round(mean(is.na(.x)) * 100, 1)))


4.5.1.1 NA 처리 전략

# 전략 1: NA가 있는 행 제거 (Complete Case Analysis)
csa_complete &lt;- csa_tdm |&gt;
  filter(!is.na(concentration))

# 전략 2: 특정 값으로 대체
csa_filled &lt;- csa_tdm |&gt;
  mutate(
    concentration = replace_na(concentration, 0)
  )

# 전략 3: 이전/다음 값으로 채우기 (LOCF: Last Observation Carried Forward)
csa_locf &lt;- csa_tdm |&gt;
  group_by(patient_id) |&gt;
  arrange(visit) |&gt;
  mutate(
    concentration = if_else(
      is.na(concentration),
      lag(concentration),  # 이전 값으로 대체
      concentration
    )
  ) |&gt;
  ungroup()

# 전략 4: 그룹 평균으로 대체
csa_mean_impute &lt;- csa_tdm |&gt;
  group_by(patient_id, sample_type) |&gt;
  mutate(
    concentration = if_else(
      is.na(concentration),
      mean(concentration, na.rm = TRUE),
      concentration
    )
  ) |&gt;
  ungroup()




4.5.2 BLQ (Below Limit of Quantification) 처리






그림 4.2: BLQ 처리 방법 의사결정 트리 (BLQ Handling Methods Decision Tree). BLQ 검출 시 의사결정 과정을 트리 형태로 도식화하였다. Pre-dose 여부에 따라 Method M1(0으로 대체), Post-Cmax 여부에 따라 M5(LOQ/2) 또는 M3(censored 처리) 등의 방법을 선택하는 과정을 보여준다.



그림 4.2 은 BLQ 데이터의 처리 과정을 보여줍니다. BLQ 데이터의 처리는 약동학 분석에서 매우 중요한 통계적/약리학적 의미를 갖습니다. BLQ 값을 어떻게 처리하느냐에 따라 PK 파라미터 추정치가 달라질 수 있습니다.






노트BLQ란 무엇인가?



BLQ (Below Limit of Quantification)는 분석법(assay)의 정량한계(LOQ, Limit of Quantification) 미만의 농도를 말합니다. 약물이 존재하지만 정확히 정량할 수 없는 농도입니다.
예를 들어, Cyclosporine 분석법의 LOQ가 10 ng/mL이라면, 실제 농도가 5 ng/mL인 경우 “BLQ” 또는 “&lt; 10”으로 보고됩니다.



4.5.2.1 BLQ 처리 방법 (M1-M7)
FDA 및 EMA 가이드라인에서 권장하는 주요 BLQ 처리 방법은 다음과 같습니다:

# BLQ 처리 방법 요약
blq_methods &lt;- tibble(
  method = paste0("M", 1:7),
  description = c(
    "BLQ를 모두 0으로 대체",
    "BLQ를 LOQ/2로 대체",
    "BLQ를 NA로 처리 (제거)",
    "첫 번째 BLQ는 LOQ/2, 이후는 0",
    "첫 번째 BLQ는 LOQ/2, 이후는 제거",
    "Maximum Likelihood 방법",
    "Beal의 M3 방법 (NONMEM)"
  ),
  nca_use = c(
    "간단하지만 AUC 과소평가",
    "가장 널리 사용, NCA에 적합",
    "간단하지만 정보 손실",
    "Trough에 BLQ가 많을 때 유용",
    "일반적으로 권장",
    "모집단 PK에서 사용",
    "모집단 PK에서 권장"
  ),
  complexity = c("낮음", "낮음", "낮음", "중간", "중간", "높음", "높음")
)

blq_methods



4.5.2.2 BLQ 처리 함수 구현

# BLQ 처리 함수
handle_blq &lt;- function(data, conc_col = "concentration",
                       blq_col = "blq_flag", loq = 10,
                       method = "M5") {

  data &lt;- data |&gt;
    arrange(patient_id, time_hr)  # 시간순 정렬 필수

  if (method == "M1") {
    # M1: BLQ → 0
    data |&gt;
      mutate(
        conc_handled = if_else(.data[[blq_col]], 0, .data[[conc_col]])
      )

  } else if (method == "M2") {
    # M2: BLQ → LOQ/2
    data |&gt;
      mutate(
        conc_handled = if_else(.data[[blq_col]], loq / 2, .data[[conc_col]])
      )

  } else if (method == "M3") {
    # M3: BLQ → NA (제거)
    data |&gt;
      mutate(
        conc_handled = if_else(.data[[blq_col]], NA_real_, .data[[conc_col]])
      )

  } else if (method == "M5") {
    # M5: 첫 번째 BLQ → LOQ/2, 이후 연속 BLQ → 제거
    data |&gt;
      group_by(patient_id) |&gt;
      mutate(
        # 연속된 BLQ의 순서 번호 계산
        blq_consecutive = if_else(
          .data[[blq_col]],
          cumsum(.data[[blq_col]]) -
            cummax(cumsum(!.data[[blq_col]]) * .data[[blq_col]]),
          0L
        ),
        conc_handled = case_when(
          !.data[[blq_col]] ~ .data[[conc_col]],
          blq_consecutive == 1 ~ loq / 2,    # 첫 번째 BLQ
          TRUE ~ NA_real_                      # 이후 BLQ → NA
        )
      ) |&gt;
      ungroup()

  } else {
    stop("지원하지 않는 방법: ", method, ". M1, M2, M3, M5 중 선택하세요.")
  }
}


# BLQ 처리 함수 사용 예시
# 테스트 데이터
test_blq &lt;- tibble(
  patient_id = rep("PT001", 8),
  time_hr = c(0, 1, 2, 4, 8, 12, 16, 24),
  concentration = c(0, 850, 620, 310, 120, 45, 8, 3),
  blq_flag = c(TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, TRUE)
)

# 각 방법으로 처리
test_blq |&gt; handle_blq(loq = 10, method = "M1") |&gt; select(time_hr, conc_handled)
test_blq |&gt; handle_blq(loq = 10, method = "M2") |&gt; select(time_hr, conc_handled)
test_blq |&gt; handle_blq(loq = 10, method = "M3") |&gt; select(time_hr, conc_handled)
test_blq |&gt; handle_blq(loq = 10, method = "M5") |&gt; select(time_hr, conc_handled)







중요BLQ 처리 방법 선택 시 고려사항




NCA 분석: M5 방법이 일반적으로 권장됩니다. 첫 BLQ는 LOQ/2로, 이후 연속 BLQ는 제거합니다.
모집단 PK 모델링: M3 또는 M7 (Beal’s M3) 방법이 권장됩니다. BLQ를 censored observation으로 처리합니다.
BLQ 비율 확인: BLQ 비율이 10% 이하이면 처리 방법에 따른 결과 차이가 크지 않습니다. 30% 이상이면 방법 선택이 중요합니다.
프로토콜/SAP 확인: 임상시험에서는 통계분석계획서(SAP)에 BLQ 처리 방법이 사전 정의되어 있어야 합니다.






4.5.3 NA와 BLQ의 시각화

# 결측 패턴 시각화
library(naniar)  # 결측치 시각화 패키지

# 결측 패턴 요약
gg_miss_var(csa_tdm)

# 농도 데이터에서 BLQ와 NA 분포
csa_tdm |&gt;
  mutate(
    data_status = case_when(
      blq_flag ~ "BLQ",
      is.na(concentration) ~ "Missing",
      TRUE ~ "Quantifiable"
    )
  ) |&gt;
  count(sample_type, data_status) |&gt;
  ggplot(aes(x = sample_type, y = n, fill = data_status)) +
  geom_col(position = "stack") +
  labs(
    title = "채혈 시점별 데이터 상태 분포",
    x = "채혈 시점", y = "관측 수", fill = "데이터 상태"
  ) +
  theme_minimal()

6.5 기술통계 테이블 작성

6.5.1 gtsummary::tbl_summary()로 인구통계학적 요약
인구통계학적 요약표(demographic summary table)는 모든 임상시험 보고서의 첫 번째 표입니다. gtsummary 패키지를 사용하면 출판 수준의 요약표를 쉽게 만들 수 있습니다.

library(gtsummary)

# 인구통계학적 요약표
demo_table &lt;- patient_params |&gt;
  select(dose_mg, weight_kg, age, sex) |&gt;
  mutate(dose_group = paste0(dose_mg, " mg")) |&gt;
  select(-dose_mg) |&gt;
  tbl_summary(
    by = dose_group,
    statistic = list(
      all_continuous() ~ "{mean} ({sd})",
      all_categorical() ~ "{n} ({p}%)"
    ),
    digits = list(
      all_continuous() ~ 1,
      all_categorical() ~ c(0, 1)
    ),
    label = list(
      weight_kg ~ "체중 (kg)",
      age ~ "나이 (세)",
      sex ~ "성별"
    ),
    missing_text = "결측"
  ) |&gt;
  add_overall() |&gt;
  modify_header(label ~ "**변수**") |&gt;
  modify_spanning_header(
    all_stat_cols() ~ "**용량군**"
  ) |&gt;
  bold_labels()

demo_table


# 연속형 변수에 중앙값(범위) 추가
demo_table_extended &lt;- patient_params |&gt;
  select(dose_mg, weight_kg, age, sex) |&gt;
  mutate(dose_group = paste0(dose_mg, " mg")) |&gt;
  select(-dose_mg) |&gt;
  tbl_summary(
    by = dose_group,
    statistic = list(
      all_continuous() ~ c(
        "{mean} ({sd})",
        "{median} [{min}, {max}]"
      ),
      all_categorical() ~ "{n} ({p}%)"
    ),
    type = list(
      all_continuous() ~ "continuous2"
    ),
    label = list(
      weight_kg ~ "체중 (kg)",
      age ~ "나이 (세)",
      sex ~ "성별"
    )
  ) |&gt;
  add_overall()

demo_table_extended



6.5.2 gt 패키지로 PK 파라미터 요약표
PK 파라미터 요약표는 기하평균, %CV를 포함하는 것이 표준입니다:

library(gt)

# PK 파라미터 요약 계산
pk_param_summary &lt;- pk_params |&gt;
  group_by(dose_group = paste0(dose_mg, " mg")) |&gt;
  summarise(
    N = n(),
    # Cmax
    Cmax_mean = round(mean(Cmax, na.rm = TRUE), 1),
    Cmax_sd = round(sd(Cmax, na.rm = TRUE), 1),
    Cmax_cv = round(sd(Cmax, na.rm = TRUE) / mean(Cmax, na.rm = TRUE) * 100, 1),
    Cmax_gmean = round(geometric_mean(Cmax), 1),
    Cmax_gcv = round(geometric_cv(Cmax), 1),
    Cmax_median = round(median(Cmax, na.rm = TRUE), 1),
    Cmax_range = paste0(round(min(Cmax, na.rm = TRUE), 1), " - ",
                        round(max(Cmax, na.rm = TRUE), 1)),
    # Tmax
    Tmax_median = median(Tmax, na.rm = TRUE),
    Tmax_range = paste0(min(Tmax, na.rm = TRUE), " - ",
                        max(Tmax, na.rm = TRUE)),
    .groups = "drop"
  )

# gt 테이블 생성
pk_param_summary |&gt;
  gt() |&gt;
  tab_header(
    title = md("**Cyclosporine PK 파라미터 요약**"),
    subtitle = "아토피 피부염 환자 대상 약동학 연구"
  ) |&gt;
  cols_label(
    dose_group = "용량군",
    N = "N",
    Cmax_mean = "평균",
    Cmax_sd = "SD",
    Cmax_cv = "%CV",
    Cmax_gmean = "기하평균",
    Cmax_gcv = "기하%CV",
    Cmax_median = "중앙값",
    Cmax_range = "범위",
    Tmax_median = "중앙값",
    Tmax_range = "범위"
  ) |&gt;
  tab_spanner(
    label = md("**Cmax (ng/mL)**"),
    columns = starts_with("Cmax")
  ) |&gt;
  tab_spanner(
    label = md("**Tmax (hr)**"),
    columns = starts_with("Tmax")
  ) |&gt;
  tab_footnote(
    footnote = "기하평균 = exp(mean(log(x))); 기하%CV = sqrt(exp(var(log(x)))-1) × 100",
    locations = cells_column_labels(columns = c(Cmax_gmean, Cmax_gcv))
  ) |&gt;
  tab_footnote(
    footnote = "Tmax는 중앙값(범위)으로 보고 (순서형 변수)",
    locations = cells_column_labels(columns = Tmax_median)
  ) |&gt;
  tab_source_note(
    source_note = "BLQ 값은 분석에서 제외"
  ) |&gt;
  tab_options(
    table.font.size = px(12),
    heading.title.font.size = px(16)
  )



6.5.3 기하평균, %CV 포함 종합 테이블
실제 임상시험 보고서에서 사용하는 형태의 종합 PK 파라미터 요약표를 작성합니다:

# 종합 PK 요약 함수
create_pk_summary_table &lt;- function(data, param_col, param_name, unit) {

  data |&gt;
    summarise(
      Parameter = param_name,
      Unit = unit,
      N = sum(!is.na(.data[[param_col]])),
      `Arithmetic Mean` = round(mean(.data[[param_col]], na.rm = TRUE), 1),
      SD = round(sd(.data[[param_col]], na.rm = TRUE), 1),
      `%CV` = round(sd(.data[[param_col]], na.rm = TRUE) /
                      mean(.data[[param_col]], na.rm = TRUE) * 100, 1),
      `Geometric Mean` = round(geometric_mean(.data[[param_col]]), 1),
      `Geometric %CV` = round(geometric_cv(.data[[param_col]]), 1),
      Median = round(median(.data[[param_col]], na.rm = TRUE), 1),
      Min = round(min(.data[[param_col]], na.rm = TRUE), 1),
      Max = round(max(.data[[param_col]], na.rm = TRUE), 1)
    )
}

# 전체 데이터에 대한 요약표 (Tmax 제외 - 별도 처리)
pk_overall_summary &lt;- bind_rows(
  create_pk_summary_table(pk_params, "Cmax", "Cmax", "ng/mL"),
  create_pk_summary_table(pk_params, "C0", "C0 (Trough)", "ng/mL"),
  create_pk_summary_table(pk_params, "C2", "C2", "ng/mL")
)

# gt 테이블
pk_overall_summary |&gt;
  gt() |&gt;
  tab_header(
    title = md("**Cyclosporine PK 파라미터 요약 (전체)**"),
    subtitle = "N=20, 아토피 피부염 환자"
  ) |&gt;
  fmt_number(
    columns = c(`Arithmetic Mean`, SD, `%CV`,
                `Geometric Mean`, `Geometric %CV`,
                Median, Min, Max),
    decimals = 1
  ) |&gt;
  tab_options(
    table.font.size = px(11),
    heading.title.font.size = px(15)
  )
